// headless:string → 有序、带规则名的解题步骤(无 DOM 足迹)
import { simplifyExpression, solveEquation, factor, ChangeTypes } from 'https://cdn.jsdelivr.net/npm/mathsteps@0.2.0/+esm';
const run = { simplify: simplifyExpression, solve: solveEquation, factor }[data.mode ?? 'solve'];
const steps = run(data.input);
const text = (node, eq) => node ? node.toString() : eq.ascii(); // simplify 用 node,solve 用 equation
const rendered = steps.map(s => ({ rule: s.changeType, before: text(s.oldNode, s.oldEquation), after: text(s.newNode, s.newEquation), substeps: s.substeps?.length ?? 0 }));
